// Check if current time is outside business hours (Mon-Fri 9am-5pm CST)
const now = new Date();
// Convert to CST (UTC-6, or UTC-5 during daylight saving)
const cstOffset = -6 * 60; // minutes
const utcMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const cstMinutes = ((utcMinutes + cstOffset) + 1440) % 1440;
const cstHour = Math.floor(cstMinutes / 60);
const dayOfWeek = new Date(now.getTime() + cstOffset * 60 * 1000).getUTCDay(); // 0=Sun, 6=Sat

const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
const isBeforeOpen = cstHour < 9;
const isAfterClose = cstHour >= 17;
const isAfterHours = isWeekend || isBeforeOpen || isAfterClose;

return [{ json: { ...$input.first().json, isAfterHours, cstHour, dayOfWeek } }];

const body = $input.first().json.body || {};
// Tawk.to sends visitor info in different fields depending on event type
const visitorName = body.visitor?.name || body.chat?.visitor?.name || 'Someone';
const visitorEmail = body.visitor?.email || body.chat?.visitor?.email || 'no email';
const message = body.message?.text || body.chat?.message?.text || '(no message text)';
const event = body.event || 'chat_started';

return [{ json: { visitorName, visitorEmail, message, event } }];
